import numpy as np
from collections import defaultdict

class LSHIndex:
    def __init__(self, num_hyperplanes: int, dim: int, num_tables: int, seed: int = 0):
        self.num_hyperplanes = num_hyperplanes
        self.dim = dim
        self.num_tables = num_tables
        rng = np.random.RandomState(seed)
        # Random hyperplanes: (num_tables, num_hyperplanes, dim)
        self.hyperplanes = rng.randn(num_tables, num_hyperplanes, dim)
        # Each table maps hash_code (tuple of bits) -> list of (vector, doc_id)
        self.tables = [defaultdict(list) for _ in range(num_tables)]
        self.all_vectors = []  # store all (vector, doc_id) for re-ranking

    def _hash(self, vector: np.ndarray, table_idx: int) -> tuple:
        projections = self.hyperplanes[table_idx] @ vector  # (num_hyperplanes,)
        bits = tuple((projections >= 0).astype(int).tolist())
        return bits

    def add(self, vector: np.ndarray, doc_id) -> None:
        norm_vec = vector / np.linalg.norm(vector)
        self.all_vectors.append((norm_vec, doc_id))
        for t in range(self.num_tables):
            code = self._hash(norm_vec, t)
            self.tables[t][code].append((norm_vec, doc_id))

    def search(self, query: np.ndarray, top_k: int = 1) -> list:
        query_norm = query / np.linalg.norm(query)
        candidates = {}
        for t in range(self.num_tables):
            code = self._hash(query_norm, t)
            for vec, doc_id in self.tables[t].get(code, []):
                if doc_id not in candidates:
                    candidates[doc_id] = vec
        # If not enough candidates, fall back to full scan
        if len(candidates) < top_k:
            candidates = {doc_id: vec for vec, doc_id in self.all_vectors}
        # Re-rank by cosine similarity
        scored = [(float(query_norm @ vec), doc_id) for doc_id, vec in candidates.items()]
        scored.sort(key=lambda x: -x[0])
        return [doc_id for _, doc_id in scored[:top_k]]

pytorch_solution_code:
import torch
import torch.nn.functional as F
from collections import defaultdict

class LSHIndex:
    def __init__(self, num_hyperplanes: int, dim: int, num_tables: int, seed: int = 0):
        self.num_hyperplanes = num_hyperplanes
        self.num_tables = num_tables
        gen = torch.manual_seed(seed)
        self.hyperplanes = torch.randn(num_tables, num_hyperplanes, dim, generator=gen)
        self.tables = [defaultdict(list) for _ in range(num_tables)]
        self.all_vectors = []

    def _hash(self, vector: torch.Tensor, table_idx: int) -> tuple:
        projections = self.hyperplanes[table_idx] @ vector
        bits = tuple((projections >= 0).int().tolist())
        return bits

    def add(self, vector: torch.Tensor, doc_id) -> None:
        vector = torch.as_tensor(vector, dtype=torch.float32)
        norm_vec = F.normalize(vector, dim=0)
        self.all_vectors.append((norm_vec, doc_id))
        for t in range(self.num_tables):
            code = self._hash(norm_vec, t)
            self.tables[t][code].append((norm_vec, doc_id))

    def search(self, query: torch.Tensor, top_k: int = 1) -> list:
        query = torch.as_tensor(query, dtype=torch.float32)
        query_norm = F.normalize(query, dim=0)
        candidates = {}
        for t in range(self.num_tables):
            code = self._hash(query_norm, t)
            for vec, doc_id in self.tables[t].get(code, []):
                if doc_id not in candidates:
                    candidates[doc_id] = vec
        if len(candidates) < top_k:
            candidates = {doc_id: vec for vec, doc_id in self.all_vectors}
        scored = [(float(torch.dot(query_norm, vec)), doc_id) for doc_id, vec in candidates.items()]
        scored.sort(key=lambda x: -x[0])
        return [doc_id for _, doc_id in scored[:top_k]]
